1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = { op: "quote"; items: Item[] };
9	export type Step = QuoteStep;
10	
11	export type Scenario = {
12	  customer: { yearsWithMHPCO: number };
13	  steps: Step[];
14	};
15	
16	export type QuoteResult = { premium: number };
17	export type StepResult = QuoteResult;
18	export type ScenarioResult = { results: StepResult[] };
19	
20	const PROCESSING_FEE = 5;
21	// Surcharge expressed in tenths of base premium to keep arithmetic in integers
22	// until the final rounding step (avoids 100 * 1.1 = 110.00000000000001).
23	const FIRST_INSURANCE_TENTHS = 1;
24	
25	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	};
30	
31	const basePremium = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
32	
33	const itemPremiumTenths = (item: Item): number =>
34	  basePremium(item) * (10 + FIRST_INSURANCE_TENTHS);
35	
36	const quote = (step: QuoteStep): QuoteResult => {
37	  const itemsTotalTenths = step.items.reduce((sum, item) => sum + itemPremiumTenths(item), 0);
38	  return { premium: Math.ceil(itemsTotalTenths / 10) + PROCESSING_FEE };
39	};
40	
41	export const runScenario = (scenario: Scenario): ScenarioResult => {
42	  return { results: scenario.steps.map(quote) };
43	};
